import { describe, expect, it } from '@a0n/gnosis/test';
import { runBraidFastPathBenchmark } from './braid-fast-path-benchmark';

describe('braid fast-path benchmark', () => {
  it('captures certified braid metadata and decision avoidance', async () => {
    const report = await runBraidFastPathBenchmark({
      iterations: 8,
      warmup: 2,
    });

    expect(report.label).toBe('gnosis-braid-fast-path-benchmark-v1');
    expect(report.scheduleKinds).toEqual([
      'parallel',
      'collapse',
      'linear',
      'linear',
    ]);
    expect(report.runtimeModuleMetadata.emitted).toBe(true);
    expect(report.runtimeModuleMetadata.braidFoldDirective).toBe(true);
    expect(report.runtimeModuleMetadata.decompositionTripleDirective).toBe(
      true
    );
    expect(report.runtimeModuleMetadata.braidPacketDirective).toBe(true);
    expect(report.runtimeModuleMetadata.extendedAeonDirective).toBe(true);
    expect(report.runtimeModuleMetadata.interferePortDirective).toBe(true);
    expect(
      report.runtimeModuleMetadata.pressureWeightedInterferenceDirective
    ).toBe(true);
    expect(report.runtimeModuleMetadata.braidFoldCertified).toBe(true);
    expect(report.runtimeModuleMetadata.decompositionTripleCertified).toBe(
      true
    );
    expect(report.runtimeModuleMetadata.braidPacketCertified).toBe(true);
    expect(report.runtimeModuleMetadata.extendedAeonCertified).toBe(true);
    expect(report.runtimeModuleMetadata.interferePortCertified).toBe(true);
    expect(
      report.runtimeModuleMetadata.pressureWeightedInterferenceCertified
    ).toBe(true);
    expect(report.selected.status).toBe('selected');
    expect(report.fallback.status).toBe('fallback');
    expect(report.selected.semanticMismatches).toBe(0);
    expect(report.fallback.semanticMismatches).toBe(0);
    expect(report.comparison.semanticMismatches).toBe(0);
    expect(report.selected.totalRuntimeDecisions).toBe(0);
    expect(report.selected.totalAvoidedRuntimeDecisions).toBeGreaterThan(0);
    expect(report.fallback.totalRuntimeDecisions).toBeGreaterThan(0);
    expect(report.fallback.totalAvoidedRuntimeDecisions).toBe(0);
    expect(report.comparison.runtimeDecisionDelta).toBeGreaterThan(0);
    expect(report.comparison.avoidedRuntimeDecisionDelta).toBeGreaterThan(0);
  });
});
